import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const ProgrammeMaster = () => {
    const [programmes, setProgrammes] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', programmeShortName: '' });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchProgrammes();
        fetchDepartments();
    }, []);

    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) {
            alert('Error fetching programmes');
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/programme', formData);
            setFormData({ department: '', programme: '', programmeShortName: '' });
            fetchProgrammes();
            alert('Programme added successfully!');
        } catch (err) {
            alert('Error adding programme');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Programme Master</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Department</label>
                    <select 
                        required
                        value={formData.department}
                        onChange={e => setFormData({...formData, department: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">Select Department</option>
                        {departments.map(dept => (
                            <option key={dept._id} value={dept._id}>{dept.department}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Programme Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.programme}
                        onChange={e => setFormData({...formData, programme: e.target.value})}
                        style={inputStyle}
                    />
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Programme Short Name</label>
                    <input 
                        type="text" 
                        required
                        value={formData.programmeShortName}
                        onChange={e => setFormData({...formData, programmeShortName: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add Programme'}
                </button>
            </form>

            <h3>Programmes List</h3>
            <table style={tableStyle}>
                <thead>
                    <tr>
                        <th>Department</th>
                        <th>Programme Name</th>
                        <th>Short Name</th>
                    </tr>
                </thead>
                <tbody>
                    {programmes.map(prog => (
                        <tr key={prog._id}>
                            <td>{prog.department?.department}</td>
                            <td>{prog.programme}</td>
                            <td>{prog.programmeShortName}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default ProgrammeMaster;
